#!/bin/sh
# cargo-loco-generate-scaffold/generate.sh
#
# Generator script for Loco scaffolding.
#
# Run from inside a fresh Loco project (one created via
# `loco new --name <form-slug> --db postgres --bg async --assets serverside`)
# to scaffold every CRUD resource for this form. Tables are scaffolded in the
# same order as the form's sql-migrations/ so that FK targets already exist
# when referencing tables are created.
#
# Generated by bin/generate-cargo-loco-scaffold.py from sql-migrations/*.sql.
# Do not edit by hand — re-run the generator after changing the SQL migrations.

set -euf


echo "Scaffolding occupational-therapy-assessment (17 tables)..."

cargo loco generate scaffold patient \
    first_name:string! \
    last_name:string! \
    date_of_birth:date! \
    nhs_number:string^ \
    sex:string! \
    weight_kg:double \
    height_cm:double \
    bmi:double \
    --htmx

cargo loco generate scaffold assessment \
    patient:references \
    status:string! \
    --htmx

cargo loco generate scaffold assessment_demographics \
    assessment:references \
    first_name:string! \
    last_name:string! \
    date_of_birth:date \
    sex:string! \
    phone:string! \
    email:string! \
    address:text! \
    occupation:string! \
    employer:string! \
    living_situation:string! \
    primary_hand:string! \
    --htmx

cargo loco generate scaffold assessment_referral_information \
    assessment:references \
    referral_source:string! \
    referral_source_details:text! \
    referring_clinician_name:string! \
    referring_clinician_role:string! \
    referral_date:date \
    referral_reason:text! \
    primary_diagnosis:text! \
    secondary_diagnoses:text! \
    precautions:text! \
    previous_ot_involvement:string! \
    previous_ot_details:text! \
    --htmx

cargo loco generate scaffold assessment_self_care_activities \
    assessment:references \
    personal_care_independence:string! \
    dressing_ability:string! \
    bathing_ability:string! \
    feeding_ability:string! \
    toileting_ability:string! \
    mobility_indoors:string! \
    medication_management:string! \
    self_care_concerns:text! \
    assistive_devices_used:text! \
    self_care_notes:text! \
    --htmx

cargo loco generate scaffold assessment_productivity_activities \
    assessment:references \
    employment_status:string! \
    work_duties_description:text! \
    work_limitations:text! \
    household_management:string! \
    meal_preparation:string! \
    financial_management:string! \
    community_access:string! \
    driving_status:string! \
    childcare_responsibilities:string! \
    childcare_details:text! \
    productivity_concerns:text! \
    productivity_notes:text! \
    --htmx

cargo loco generate scaffold assessment_leisure_activities \
    assessment:references \
    quiet_recreation:text! \
    active_recreation:text! \
    socialisation:text! \
    hobbies_and_interests:text! \
    leisure_participation_level:string! \
    barriers_to_leisure:text! \
    previous_leisure_activities:text! \
    activities_given_up:text! \
    leisure_satisfaction:string! \
    leisure_concerns:text! \
    leisure_notes:text! \
    --htmx

cargo loco generate scaffold assessment_performance_ratings \
    assessment:references \
    overall_performance_score:double \
    self_care_performance_score:double \
    productivity_performance_score:double \
    leisure_performance_score:double \
    performance_notes:text! \
    --htmx

cargo loco generate scaffold assessment_performance_rating_item \
    performance_ratings:references \
    occupational_issue:string! \
    domain:string! \
    importance_score:int \
    performance_score:int \
    sort_order:int! \
    --htmx

cargo loco generate scaffold assessment_satisfaction_ratings \
    assessment:references \
    overall_satisfaction_score:double \
    self_care_satisfaction_score:double \
    productivity_satisfaction_score:double \
    leisure_satisfaction_score:double \
    satisfaction_notes:text! \
    --htmx

cargo loco generate scaffold assessment_satisfaction_rating_item \
    satisfaction_ratings:references \
    occupational_issue:string! \
    domain:string! \
    satisfaction_score:int \
    sort_order:int! \
    --htmx

cargo loco generate scaffold assessment_environmental_factors \
    assessment:references \
    home_type:string! \
    home_type_details:text! \
    number_of_floors:int \
    stairs_access:string! \
    stair_rail_present:string! \
    bathroom_accessibility:string! \
    kitchen_accessibility:string! \
    bedroom_location:string! \
    home_modifications_in_place:text! \
    home_modifications_recommended:text! \
    transport_access:text! \
    community_resources:text! \
    social_support_network:text! \
    environmental_barriers:text! \
    environmental_facilitators:text! \
    environmental_notes:text! \
    --htmx

cargo loco generate scaffold assessment_physical_cognitive_status \
    assessment:references \
    upper_limb_function:string! \
    lower_limb_function:string! \
    grip_strength_left_kg:double \
    grip_strength_right_kg:double \
    pinch_strength_left_kg:double \
    pinch_strength_right_kg:double \
    balance_sitting:string! \
    balance_standing:string! \
    endurance_level:string! \
    pain_level:int \
    pain_location:text! \
    sensation:string! \
    cognition_orientation:string! \
    cognition_memory:string! \
    cognition_attention:string! \
    cognition_executive_function:string! \
    cognition_perception:string! \
    vision:string! \
    hearing:string! \
    physical_cognitive_notes:text! \
    --htmx

cargo loco generate scaffold assessment_goals_priorities \
    assessment:references \
    patient_identified_priorities:text! \
    short_term_goals:text! \
    long_term_goals:text! \
    expected_outcomes:text! \
    intervention_plan:text! \
    estimated_treatment_duration:string! \
    treatment_frequency:string! \
    discharge_criteria:text! \
    patient_agreement:string! \
    carer_involvement:string! \
    carer_involvement_details:text! \
    onward_referrals:text! \
    goals_notes:text! \
    --htmx

cargo loco generate scaffold grading_result \
    assessment:references \
    performance_mean_score:double \
    satisfaction_mean_score:double \
    performance_category:string! \
    satisfaction_category:string! \
    graded_at:ts! \
    --htmx

cargo loco generate scaffold grading_fired_rule \
    grading_result:references \
    rule_id:string! \
    category:string! \
    description:text! \
    severity_level:string! \
    --htmx

cargo loco generate scaffold grading_additional_flag \
    grading_result:references \
    flag_id:string! \
    category:string! \
    message:text! \
    priority:string! \
    --htmx

echo "Done."
